import { RAGFlowAvatar } from '@/components/ragflow-avatar';
import { Button } from '@/components/ui/button';
import { useNavigatePage } from '@/hooks/logic-hooks/navigate-hooks';
import { useSecondPathName } from '@/hooks/route-hook';
import {
  useFetchKnowledgeBaseConfiguration,
  useFetchKnowledgeGraph,
} from '@/hooks/use-knowledge-request';
import { cn, formatBytes } from '@/lib/utils';
import { Routes } from '@/routes';
import { formatPureDate } from '@/utils/date';
import { isEmpty } from 'lodash';
import {
  Banknote,
  ChevronLeft,
  Database,
  FileSearch2,
  GitGraph,
} from 'lucide-react';
import { useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { useLocation, useNavigate, useSearchParams } from 'umi';
import { useHandleMenuClick } from './hooks';
import styles from './index.less';

type PropType = {
  refreshCount?: number;
};

export function SideBar({ refreshCount }: PropType) {
  const pathName = useSecondPathName();
  const { pathname } = useLocation();
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const { handleMenuClick } = useHandleMenuClick();
  const { navigateToDatasetList } = useNavigatePage();
  const knowledgeId = searchParams.get('id');
  // refreshCount: be for avatar img sync update on top left
  const { data } = useFetchKnowledgeBaseConfiguration(refreshCount);
  const { data: routerData } = useFetchKnowledgeGraph();
  const { t } = useTranslation();

  const items = useMemo(() => {
    const list = [
      // {
      //   icon: DatabaseZap,
      //   label: t(`knowledgeDetails.overview`),
      //   key: Routes.DataSetOverview,
      // },
      {
        icon: Database,
        label: t(`knowledgeDetails.dataset`),
        key: Routes.DatasetBase,
      },
      {
        icon: FileSearch2,
        label: t(`knowledgeDetails.testing`),
        key: Routes.DatasetTesting,
      },
      {
        icon: Banknote,
        label: t(`knowledgeDetails.configuration`),
        key: Routes.DatasetSetting,
      },
    ];
    if (!isEmpty(routerData?.graph)) {
      list.push({
        icon: GitGraph,
        label: t(`knowledgeDetails.knowledgeGraph`),
        key: Routes.KnowledgeGraph,
      });
    }
    return list;
  }, [t, routerData]);

  return (
    <aside className={styles.sidebar}>
      <button
        type="button"
        className={styles.backButton}
        onClick={() => {
          if (pathname.startsWith('/chunk/parsed/chunks') && knowledgeId) {
            navigate(`${Routes.Dataset}/${knowledgeId}`);
            return;
          }
          navigateToDatasetList();
        }}
      >
        <ChevronLeft className="size-4" />
        <span>{t('common.back', { defaultValue: '返回' })}</span>
      </button>

      <div className={styles.summaryCard}>
        <div className={styles.summaryHeader}>
          <RAGFlowAvatar
            avatar={data.avatar}
            name={data.name}
            className="size-14"
          ></RAGFlowAvatar>
          <div className={styles.summaryMeta}>
            <h3 className={styles.summaryTitle}>{data.name}</h3>
            <div className={styles.summaryCreated}>
              {t('knowledgeDetails.created')} {formatPureDate(data.create_time)}
            </div>
          </div>
        </div>
        <div className={styles.summaryStats}>
          <div className={styles.summaryStatItem}>
            <div className={styles.summaryStatLabel}>
              {t('knowledgeDetails.fileCount')}
            </div>
            <div className={styles.summaryStatValue}>{data.doc_num}</div>
          </div>
          <div className={styles.summaryStatItem}>
            <div className={styles.summaryStatLabel}>
              {t('knowledgeDetails.fileSize')}
            </div>
            <div className={styles.summaryStatValue}>
              {formatBytes(data.size)}
            </div>
          </div>
        </div>
      </div>

      <div className={styles.menuList}>
        {items.map((item, itemIdx) => {
          const active = pathname.startsWith('/chunk/parsed/chunks')
            ? item.key === Routes.DatasetBase
            : '/' + pathName === item.key;
          return (
            <Button
              key={itemIdx}
              variant={'ghost'}
              className={cn(styles.menuButton, {
                [styles.menuButtonActive]: active,
              })}
              onClick={handleMenuClick(item.key)}
            >
              <item.icon className="size-4" />
              <span>{item.label}</span>
            </Button>
          );
        })}
      </div>
    </aside>
  );
}
